  const STYLE_ID = 'renda-vigilia-chatgpt-style';
  const ROOT_CLASS = 'renda-chatgpt-root';
  const STORAGE_KEY = 'rendaVigiliaHudCollapsed';
  const PP_KEY = 'rendaVigiliaPerpetualPrompt';
